   196→// values (same order as the VariableLabels in Desc). If that combination of
   197→// label values is accessed for the first time, a new Counter is created IFF the counterVec
   198→// has been registered to a metrics registry.
   199→func (v *CounterVec) WithLabelValues(lvs ...string) CounterMetric {
   200→	if !v.IsCreated() {
   201→		return noop // return no-op counter
   202→	}
   203→
   204→	// Initialize label allow lists if not already initialized
   205→	v.initializeLabelAllowListsOnce.Do(func() {
   206→		allowListLock.RLock()
   207→		if allowList, ok := labelValueAllowLists[v.FQName()]; ok {
   208→			v.LabelValueAllowLists = allowList
   209→		}
   210→		allowListLock.RUnlock()
   211→	})
   212→
   213→	// Constrain label values to allowed values
   214→	if v.LabelValueAllowLists != nil {
   215→		v.LabelValueAllowLists.ConstrainToAllowedList(v.originalLabels, lvs)
   216→	}
   217→
   218→	return v.CounterVec.WithLabelValues(lvs...)
   219→}
   220→
   221→// With returns the Counter for the given Labels map (the label names
   222→// must match those of the VariableLabels in Desc). If that label map is
   223→// accessed for the first time, a new Counter is created IFF the counterVec has
   224→// been registered to a metrics registry.
   225→func (v *CounterVec) With(labels map[string]string) CounterMetric {
   226→	if !v.IsCreated() {
   227→		return noop // return no-op counter
   228→	}
   229→
   230→	v.initializeLabelAllowListsOnce.Do(func() {
   231→		allowListLock.RLock()
   232→		if allowList, ok := labelValueAllowLists[v.FQName()]; ok {
   233→			v.LabelValueAllowLists = allowList
   234→		}
   235→		allowListLock.RUnlock()
   236→	})
   237→
   238→	if v.LabelValueAllowLists != nil {
   239→		v.LabelValueAllowLists.ConstrainLabelMap(labels)
   240→	}
   241→
   242→	return v.CounterVec.With(labels)
   243→}
   244→
   245→// Delete deletes the metric where the variable labels are the same as those
   246→// passed in as labels. It returns true if a metric was deleted.
   247→//
   248→// It is not an error if the number and names of the Labels are inconsistent
   249→// with those of the VariableLabels in Desc. However, such inconsistent Labels
   250→// can never match an actual metric, so the method will always return false in
   251→// that case.
   252→func (v *CounterVec) Delete(labels map[string]string) bool {
   253→	if !v.IsCreated() {
   254→		return false // since we haven't created the metric, we haven't deleted a metric with the passed in values
   255→	}
   256→	return v.CounterVec.Delete(labels)
   257→}
   258→
   259→// Reset deletes all metrics in this vector.
   260→func (v *CounterVec) Reset() {
   261→	if !v.IsCreated() {
   262→		return
   263→	}
   264→
   265→	v.CounterVec.Reset()
   266→}
   267→
   268→// ResetLabelAllowLists resets the label allow list for the CounterVec.
   269→// NOTE: This should only be used in test.
   270→func (v *CounterVec) ResetLabelAllowLists() {
